queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

@alex.tension[@target.id] += 2


// ── Target response action-selector ─────────────────────────────────────────
//
// After every exchange, the target's reaction is selected. Picks in order:
// fuming → thrilled → icy → warm → cool (neutral fallback).

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true


// ── SPICY exchanges (Act 1) ─────────────────────────────────────────────────

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true


// ── BOLD exchanges (Act 1) ──────────────────────────────────────────────────

