            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true


// ── MEND exchanges (Act 1) ──────────────────────────────────────────────────

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector select-exchange:
            with:
                @alex: @alex
                @target: @target
            urgent: true


// ── Master exchange selector ────────────────────────────────────────────────
//
// Tries sub-selectors in order. Each sub-selector has a `conditions` block
// gating it on @alex.intent and @alex.act, plus its own ordered candidate list.
// First selector whose conditions pass AND that successfully targets a
// candidate is the one that fires. Falls back to awkward-pause.

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

@target.buddy[@alex.id] += 1


// ── Trigger rules ───────────────────────────────────────────────────────────
//
// `run-triggers` queues every trigger-rule action as an urgent reaction. Each
// trigger has its own conditions. The drain loop picks off any that fire.
// Mirrors Prom Week's notion of "trigger rules" running after every exchange.

queue action become-friends:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action become-dating:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action become-enemies:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action set-has-crush:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true


// ── WARM exchanges (Act 1, also serves as fallback in Act 2 if act2 selector
//    doesn't match) ──────────────────────────────────────────────────────────

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true


// ── Absolute fallback ───────────────────────────────────────────────────────

queue action-selector target-response:
            with:
                @target: @target
                @alex: @alex
            urgent: true

queue action run-triggers:
            with:
                @alex: @alex
                @target: @target
            urgent: true
